  1	import { type FC, type ReactNode, useCallback, useState } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
  4	
  5	import {
  6	  k8sDelete,
  7	  type K8sGroupVersionKind,
  8	  type K8sModel,
  9	  type K8sResourceCommon,
