 11	import { Button, ButtonVariant, Modal, ModalVariant } from '@patternfly/react-core';
 12	
 13	import useToggle from '../../hooks/useToggle';
 14	import { getResourceUrl } from '../../utils/helpers/getResourceUrl';
 15	import { AlertMessageForModals } from '../components/AlertMessageForModals';
 16	import { ItemIsOwnedAlert } from '../components/ItemIsOwnedAlert';
 17	import { useModal } from '../ModalHOC/useModal';
 18	
 19	/**
 20	 * Props for the DeleteModal component
 21	 * @typedef DeleteModalProps
 22	 * @property {string} title - The title to display in the modal
 23	 * @property {K8sResourceCommon} resource - The resource object to delete
 24	 * @property {K8sModel} model - The model used for deletion
 25	 * @property {string} [redirectTo] - Optional redirect URL after deletion
 26	 */
 27	type DeleteModalProps = {
 28	  resource: K8sResourceCommon;
 29	  model: K8sModel;
 30	  title?: string;
 31	  redirectTo?: string;
 32	};
 33	
 34	/**
 35	 * A generic delete modal component
 36	 * @component
 37	 * @param {DeleteModalProps} props - Props for DeleteModal
 38	 * @returns {Element} The DeleteModal component
 39	 */
 40	export const DeleteModal: FC<DeleteModalProps> = ({ model, redirectTo, resource, title }) => {
 41	  const { t } = useForkliftTranslation();
 42	  const { toggleModal } = useModal();
 43	  const [isLoading, toggleIsLoading] = useToggle();
 44	  const navigate = useNavigate();
 45	  const [alertMessage, setAlertMessage] = useState<ReactNode>(null);
 46	
 47	  const { name, namespace } = resource?.metadata ?? {};
 48	  const owner = resource?.metadata?.ownerReferences?.[0];
 49	
 50	  const onDelete = useCallback(async () => {
 51	    const isOnResourcePage = () => {
 52	      const re = new RegExp(`/${name}(/|$)`, 'u');
 53	      return re.test(window.location.pathname);
 54	    };
 55	
 56	    toggleIsLoading();
 57	
 58	    const groupVersionKind: K8sGroupVersionKind = {
 59	      group: model.apiGroup,
 60	      kind: model.kind,
 61	      version: model.apiVersion,
 62	    };
 63	
 64	    try {
 65	      await k8sDelete({ model, resource });
 66	      if (redirectTo) {
 67	        navigate(redirectTo);
 68	      } else if (isOnResourcePage()) {
 69	        navigate(getResourceUrl({ groupVersionKind, namespace }));
 70	      }
 71	
 72	      toggleModal();
 73	    } catch (err) {
 74	      toggleIsLoading();
 75	
 76	      if (err instanceof Error) {
 77	        setAlertMessage(<AlertMessageForModals title={t('Error')} message={err.toString()} />);
 78	      } else {
 79	        setAlertMessage(<AlertMessageForModals title={t('Error')} message={t('Unknown error')} />);
 80	      }
 81	    }
 82	  }, [resource, model, name, namespace, navigate, redirectTo, t, toggleIsLoading, toggleModal]);
 83	
 84	  const actions = [
 85	    <Button key="confirm" variant={ButtonVariant.danger} onClick={onDelete} isLoading={isLoading}>
 86	      {t('Delete')}
 87	    </Button>,
 88	    <Button key="cancel" variant={ButtonVariant.secondary} onClick={toggleModal}>
 89	      {t('Cancel')}
 90	    </Button>,
 91	  ];
 92	
 93	  return (
 94	    <Modal
 95	      title={title ?? t('Delete {{model.label}}', { model })}
 96	      titleIconVariant="warning"
 97	      position="top"
 98	      showClose={false}
 99	      variant={ModalVariant.small}
100	      isOpen={true}
101	      onClose={toggleModal}
102	      actions={actions}
103	    >
104	      {namespace ? (
105	        <ForkliftTrans>
106	          Are you sure you want to delete <strong className="co-break-word">{name}</strong> in
107	          project <strong>{namespace}</strong>?
108	        </ForkliftTrans>
109	      ) : (
110	        <ForkliftTrans>
111	          Are you sure you want to delete <strong className="co-break-word">{name}</strong>?
112	        </ForkliftTrans>
113	      )}
114	      {typeof owner === 'object' && <ItemIsOwnedAlert owner={owner} namespace={namespace} />}
115	      {alertMessage}
116	    </Modal>
117	  );
118	};

